    ctUint64 low;
}

// we use a struct because user-defined value types can only be elementary value types
struct ctUint256 {
    ctUint128 high;
    ctUint128 low;
}

// we use a struct because user-defined value types can only be elementary value types
// 8 characters (in byte form) per cell and the final cell padded with zeroes if needed
struct ctString {
    ctUint64[] value;
}

struct itBool {
    ctBool ciphertext;
    bytes signature;
}
struct itUint8 {
    ctUint8 ciphertext;
    bytes signature;
}
struct itUint16 {
