            gtUint128 memory bLow = and(b, MAX_UINT64);
            gtUint128 memory bHigh = shr(b, 64);

            // Compute partial products
            pp0 = mul(aLow, bLow);
            pp1 = mul(aLow, bHigh);
            pp2 = mul(aHigh, bLow);
            pp3 = mul(aHigh, bHigh);
        }

        // Compute high and low parts
        gtUint128 memory mid = add(
            add(
                shr(pp0, 64),
                and(pp1, MAX_UINT64)
            ),
            and(pp2, MAX_UINT64)
